#define THREADS 256

inline int mirror_idx(int d, int size)
{
    if (size <= 1) return 0;
    while (d >= size || d < 0) {
        if (d >= size) d = 2 * size - 2 - d;
        else d = -d;
    }
    return d;
}

inline int read_input_pixel(__global const int *in, int sx, int sy, int x, int y)
{
    x = mirror_idx(x, sx);
    y = mirror_idx(y, sy);
    return in[y * sx + x];
}

inline int horiz_high_from_input(__global const int *in, int sx, int sy, int row, int oddX)
{
    int c = read_input_pixel(in, sx, sy, oddX, row);
    int p = read_input_pixel(in, sx, sy, oddX - 1, row);
    int n = read_input_pixel(in, sx, sy, oddX + 1, row);
    return c - (p + n) / 2;
}

inline int horiz_low_from_input(__global const int *in, int sx, int sy, int row, int evenX)
{
    int c = read_input_pixel(in, sx, sy, evenX, row);
    int o1 = mirror_idx(evenX - 1, sx);
    int o2 = mirror_idx(evenX + 1, sx);
    int d1 = horiz_high_from_input(in, sx, sy, row, o1);
    int d2 = horiz_high_from_input(in, sx, sy, row, o2);
    return c + (d1 + d2 + 2) / 4;
}

inline int read_rowpacked(__global const int *tmp, int sx, int sy, int lowW, int band, int x, int row)
{
    row = mirror_idx(row, sy);
    return (band == 0) ? tmp[row * sx + x] : tmp[row * sx + lowW + x];
}

inline int vert_high_from_rowpacked(__global const int *tmp, int sx, int sy, int lowW, int band, int x, int oddY)
{
    int c = read_rowpacked(tmp, sx, sy, lowW, band, x, oddY);
    int p = read_rowpacked(tmp, sx, sy, lowW, band, x, oddY - 1);
    int n = read_rowpacked(tmp, sx, sy, lowW, band, x, oddY + 1);
    return c - (p + n) / 2;
}

inline int vert_low_from_rowpacked(__global const int *tmp, int sx, int sy, int lowW, int band, int x, int evenY)
{
    int c = read_rowpacked(tmp, sx, sy, lowW, band, x, evenY);
    int o1 = mirror_idx(evenY - 1, sy);
    int o2 = mirror_idx(evenY + 1, sy);
    int d1 = vert_high_from_rowpacked(tmp, sx, sy, lowW, band, x, o1);
    int d2 = vert_high_from_rowpacked(tmp, sx, sy, lowW, band, x, o2);
    return c + (d1 + d2 + 2) / 4;
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid >= pixels) return;

    int off = gid * 3;
    int r = (int)d_src[off + 0];
    int g = (int)d_src[off + 1];
    int b = (int)d_src[off + 2];

    d_r[gid] = r - 128;
    d_g[gid] = g - 128;
    d_b[gid] = b - 128;
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   int pixels)
{
    int gid = (int)get_global_id(0);

    /* host launches alignedSize/9 threads; process 9 items per work-item */
    int base = gid * 9;
    for (int k = 0; k < 9; k++) {
        int idx = base + k;
        if (idx < pixels) {
            d_c[idx] = ((int)d_src[idx]) - 128;
        }
    }
}

__kernel void cl_fdwt53Kernel(__global int *input,
                              __global int *output,
                              int sizeX,
                              int sizeY,
                              int steps,
                              int WIN_SX,
                              int WIN_SY)
{
    (void)steps;
    (void)WIN_SX;
    (void)WIN_SY;

    /* serialized implementation to preserve output format */
    if (get_global_id(0) != 0 || get_global_id(1) != 0) return;

    int sx = sizeX;
    int sy = sizeY;
    int lowW = (sx + 1) >> 1;
    int highW = sx >> 1;
    int lowH = (sy + 1) >> 1;
    int highH = sy >> 1;

    int total = sx * sy;

    /* Horizontal transform: input -> output (row-packed temp: low | high per row) */
    for (int y = 0; y < sy; y++) {
        for (int lx = 0; lx < lowW; lx++) {
            int evenX = lx << 1;
            output[y * sx + lx] = horiz_low_from_input(input, sx, sy, y, evenX);
        }
        for (int hx = 0; hx < highW; hx++) {
            int oddX = (hx << 1) + 1;
            output[y * sx + lowW + hx] = horiz_high_from_input(input, sx, sy, y, oddX);
        }
    }

    /* Vertical transform + band packing: output(temp) -> input(final packed) */
    int offsetLL = 0;
    int offsetHL = lowW * lowH;
    int offsetLH = offsetHL + highW * lowH;
    int offsetHH = offsetLH + lowW * highH;

    /* horizontal-low columns -> LL / LH */
    for (int x = 0; x < lowW; x++) {
        for (int ly = 0; ly < lowH; ly++) {
            int evenY = ly << 1;
            int v = vert_low_from_rowpacked(output, sx, sy, lowW, 0, x, evenY);
            input[offsetLL + ly * lowW + x] = v;
        }
        for (int hy = 0; hy < highH; hy++) {
            int oddY = (hy << 1) + 1;
            int v = vert_high_from_rowpacked(output, sx, sy, lowW, 0, x, oddY);
            input[offsetLH + hy * lowW + x] = v;
        }
    }

    /* horizontal-high columns -> HL / HH */
    for (int x = 0; x < highW; x++) {
        for (int ly = 0; ly < lowH; ly++) {
            int evenY = ly << 1;
            int v = vert_low_from_rowpacked(output, sx, sy, lowW, 1, x, evenY);
            input[offsetHL + ly * highW + x] = v;
        }
        for (int hy = 0; hy < highH; hy++) {
            int oddY = (hy << 1) + 1;
            int v = vert_high_from_rowpacked(output, sx, sy, lowW, 1, x, oddY);
            input[offsetHH + hy * highW + x] = v;
        }
    }

    /* final: copy packed result to output buffer */
    for (int i = 0; i < total; i++) {
        output[i] = input[i];
    }
}
